INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68027cb5e3c98b0941765a8e', '交通很方便，楼下就有地铁，叫车也很方便，酒店服务员很多，都很热情。记得不要错过瀑布花园，漫步一下很漂亮，小朋友可以带点面包或饼干喂鱼哦！', '["https://dimg04.c-ctrip.com/images/0230d12000d92nq1n97AF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233m12000d939xa4E414_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-20', '花园双床房', '双床房', '家庭亲子', 68, 0, 4, 8, '["交通便利性","周边配套","前台服务"]'::jsonb, '交通便利性', '周边配套', '前台服务'),
('68027cb5e3c98b0941765a8f', '非常满意！前台小姐姐Sara还是Cara人真的很好，下次出行还会选择该酒店！', '["https://dimg04.c-ctrip.com/images/0230u12000fby6c959FCD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-31', '红棉双床套房', '套房', '家庭亲子', 38, 0, 2, 5, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027cb5e3c98b0941765a90', '有回家的感觉，休息得很好', '["https://dimg04.c-ctrip.com/images/0236r324x8v34es8951A8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/02309324x8v34es8aC377_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-06-03', '花园大床房', '大床房', '商务出差', 12, 0, 16, 4, '["整体满意度","安静程度"]'::jsonb, '整体满意度', '安静程度', NULL),
('68027cb5e3c98b0941765a91', '总体来说有达到期望 甚至超乎想象 花园酒店经久不衰  地铁就在门口 这点非常重要 广州酒家也在马路对面 但花园酒店的桃园馆更胜一筹（如果不考虑价格） 房间不大 我原来定的花园大床房 前台为了让我及时入住换成新装修的低楼层房间 会看到修路工地 这点比较失望 还有浴室设计偏小 私密性较不足 其实浴缸可以不要设置 对两人入住的不中用 洗脸盆就在离床头不远 无遮拦 如果一人先起床 还是会影响 可以忽略 早餐很丰盛 服务很好', '["https://dimg04.c-ctrip.com/images/0231x12000cusxhg2E850_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235812000cusuka67DE2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230612000cusw4kn6AE0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236f12000cusuib750FD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234h12000cusvy2c20F1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232z12000cusyeve948E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230v12000cusubjyE907_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230j12000cuslwhrF849_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232512000custti9850C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-03', '花园大床房', '大床房', '家庭亲子', 209, 0, 11, 8, '["交通便利性","周边配套","房间设施"]'::jsonb, '交通便利性', '周边配套', '房间设施'),
('68027cb5e3c98b0941765a92', '酒店门口是5号地铁线，公交车也很多，附近吃的有陶陶居和点都德，酒店里面有个早茶很好吃桃园馆
，酒店大厅有颗大大得圣诞树小朋友很喜欢，外面有个后花园。
低层楼电视机无法投屏，房间里灯不是很亮，浴缸很大，外出一天可以给孩子泡澡', '["https://dimg04.c-ctrip.com/images/0232l12000cudr81m4B26_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233512000cuds9i5FD1A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236212000cudpbtvA070_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235g12000cudn3qy6F91_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236h12000cudt90e79BB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236312000cudqphd4AE9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237112000cudu1rl5324_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-01', '花园大床房', '大床房', '家庭亲子', 111, 0, 4, 7, '["交通便利性","周边配套","房间设施"]'::jsonb, '交通便利性', '周边配套', '房间设施'),
('68027cb5e3c98b0941765a93', '老牌五星酒店，设施确实有些老旧了，房间小也确实小，有些日式的设计感。门口迎宾服务素质参差不齐，有一个歪果仁迎宾似乎不太主动，看着我们抱着娃拎着箱子和小推车上台阶，也不会主动过来帮我们。其他服务员都非常热情，非常友好且主动。有个做气球的服务生非常会逗小朋友开心。
瀑布花园设计很值得一看，池子里的锦鲤令人心情愉悦，希望好运加持。', '["https://dimg04.c-ctrip.com/images/0235c12000cv78xpj6EA9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233z12000cv766ee36BA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236j12000cv7p7c3FB6D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233z12000cv7mfm1F910_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232912000cv7j91qCC89_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232p12000cv7lbvmA709_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233912000cv7gonyDC60_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231312000cv7ik5mE1A6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-01-05', '花园大床房', '大床房', '家庭亲子', 163, 0, 7, 8, '["房间设施","前台服务","整体满意度"]'::jsonb, '房间设施', '前台服务', '整体满意度'),
('68027cc0e3c98b0941765a94', '套房非常满意，酒店很有文化底蕴。服务也很好。送入住点心和水果。还送了小羊。就是瀑布的自助餐实在是一般，大年三十588的自助实在是没啥好吃的。', '["https://dimg04.c-ctrip.com/images/0230o12000d6fji8qE318_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230b12000d6fh3b3A55B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231712000d6fh3b58849_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-11', '羊羊得意主题大床房', '主题房', '家庭亲子', 70, 0, 35, 7, '["餐饮设施","整体满意度","客房服务"]'::jsonb, '餐饮设施', '整体满意度', '客房服务'),
('68027cc0e3c98b0941765a95', '非常满意 服务什么都很好', '["https://dimg04.c-ctrip.com/images/0231012000e8jxyq8947F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-05-30', '花园大床房', '大床房', '独自旅行', 12, 0, 4, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027cc0e3c98b0941765a96', '刚入住就发现瓜子皮，根本没有服务。空调是坏的。刚进房间就发现马桶也没说。不想评价了。要是想体验服务和环境的建议别定，不值一千多。唯一亮点可能就是瀑布餐厅。', '["https://dimg04.c-ctrip.com/images/0234b12000d2ylkxtA8CA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236312000d2y6i2g725D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.2, 3, '2024-01-30', '花园双床房', '双床房', '商务出差', 77, 0, 3, 6, '["房间设施","卫生状况","性价比"]'::jsonb, '房间设施', '卫生状况', '性价比'),
('68027cc0e3c98b0941765a97', '设施：不愧是白金五星级酒店，酒店大堂非常富力堂皇且浪漫??，设计感超赞。

服务：老牌的星级酒店服务专业到位，上上下下没一位工作人员都耐心细致，过来庆祝结婚38年纪念的，酒店给升级了房间，前台给了鲜花，房间做了漂亮布置，送了蛋糕，真是惊喜到了，在此感谢每一位用心的工作人员。', '["https://dimg04.c-ctrip.com/images/0230q12000ctz1s6o0101_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234q12000ctz3u881A54_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-30', '花园双床房', '双床房', '情侣出游', 137, 0, 24, 9, '["前台服务","整体满意度","房间设施"]'::jsonb, '前台服务', '整体满意度', '房间设施'),
('68027cc0e3c98b0941765a98', '公共区域设计标准高、用材好，结合了国内传统文化，很前沿，相信多年后也不会落伍。
酒店内米其林3家，美食很棒！
房间装修及用材有提升空间。', '["https://dimg04.c-ctrip.com/images/0234012000d9otb1m1005_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236612000d9ou4nbEC3B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233c12000d9of0yt975A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230u12000d9oipezA3A3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-02-22', '花园大床房', '大床房', '家庭亲子', 68, 0, 4, 7, '["公共设施","餐饮设施","房间设施"]'::jsonb, '公共设施', '餐饮设施', '房间设施'),
('68027cc0e3c98b0941765a99', '不愧是第一个白金五星酒店，装潢和服务都很棒，适合喜欢探索一下岭南文化的旅行者。唯一美中不足就是房间里面充电的地方不够多，以及吹风机真的很难用，应该提升一下设备便利度，才不愧这么好的环境和服务。', '["https://dimg04.c-ctrip.com/images/0235k12000cvtcgkz4D33_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234y12000cvth3ua123E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232312000cvtdslyCEE7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231l12000cvtf5vg1EC4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-01-07', '红棉双床套房', '套房', '朋友出游', 96, 0, 9, 8, '["房间设施","整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL),
('68027cc0e3c98b0941765a9a', '酒店大堂背景很震撼，房间重新装修过，外面花园也很精致；台前巴基斯坦小哥DASTAAN人很nice，普通话流利，有求必应，值得推荐！', '["https://dimg04.c-ctrip.com/images/0230512000d8uce936FE9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231k12000d8ucybo2CEA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-19', '花园双床房', '双床房', '朋友出游', 65, 0, 6, 8, '["前台服务","整体满意度","房间设施"]'::jsonb, '前台服务', '整体满意度', '房间设施'),
('68027cc0e3c98b0941765a9b', '白金级酒店真没选错。虽然设施是旧了点，可是老牌星级酒店的服务真是不错，很专业的。很喜欢酒店的大厅，红楼梦巨型背景墙好有感觉，酒店的下午茶还行，最好看的就是瀑布背景，设计感超赞。酒店的位置也很好，出门右边就是地铁站，出行非常方便。', '["https://dimg04.c-ctrip.com/images/0235712000ctroyzrBA55_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235j12000ctrq5oo0F6D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232r12000ctrg2q454D8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-29', '花园双床房', '双床房', '朋友出游', 114, 0, 17, 8, '["交通便利性","整体满意度","前台服务"]'::jsonb, '交通便利性', '整体满意度', '前台服务'),
('68027cc0e3c98b0941765a9c', '又体验了另外的一种房型，虽然老，感觉比新装修的更好，空间高舒适些。各个餐厅也各有特色，瀑布餐厅偏西式，精致粤菜料理在桃园馆。老牌米其林的荔湾亭特别怀旧，西关风情浓，菜品精致，不渗假水。4楼的博物馆更是值得看看，珍藏有邓爷爷的墨宝…', '["https://dimg04.c-ctrip.com/images/0230l12000chi0nafC7B3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233m12000chhyp7iBCA1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231i12000chi6fvn7380_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233o12000chhuu37D223_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230d12000chhvp97A2C6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231l12000chhy418132B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234i12000chi3el176FF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235j12000chi5gz3CC85_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231v12000chi5iev32D2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-31', '红棉大床套房', '套房', '情侣出游', 115, 0, 114, 9, '["餐饮设施","整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL),
('68027cc0e3c98b0941765a9d', '最大的问题是房间面积小有点旧，服务非常好，大堂金碧辉煌很是气派，后花园的瀑布和环境是其他广州酒店不能比的，整个酒店到处洋溢着浓浓的春节气氛。', '["https://dimg04.c-ctrip.com/images/0235z12000d60ug776CC7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232j12000d60sundDFC5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234e12000d60tq4uEB8C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230k12000d60thpj5963_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-02-09', '城央绿意双床房', '双床房', '家庭亲子', 70, 0, 6, 8, '["房间设施","整体满意度","公共设施"]'::jsonb, '房间设施', '整体满意度', '公共设施'),
('68027ccde3c98b0941765a9e', '前台cookie小姐姐和anna小姐姐接待我们的，一流品质一流服务，浴缸独具风格，体验感满满，很爱很爱??', '["https://dimg04.c-ctrip.com/images/0235512000ipzg5a27D7F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-24', '城央绿意大床房', '大床房', '商务出差', 53, 1, 3, 6, '["前台服务","房间设施","整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度'),
('68027ccde3c98b0941765a9f', '前台接待服务非常热情，酒店设施完善，很好！！！', '["https://dimg04.c-ctrip.com/images/0234212000dv8fvz4522C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235u12000dv8lmrfA8CB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-05-03', '红棉大床套房', '套房', '家庭亲子', 23, 0, 3, 4, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027ccde3c98b0941765aa0', '五星级酒店。竞然没有夜床服务、太奇怪了??3天没有一次夜床服务。花园酒店生意太好省下了。第一天入住。2010房、洗澡间的水浸入到卫生间没法使用。换房间后。18 08。从服务员到主管没人对此说一声对不起。哈哈花园酒店牛。????????。', '["https://dimg04.c-ctrip.com/images/0233312000ctwbhvmC4EE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231y12000ctwa7i3799A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235r12000ctwa0th7A48_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-12-30', '花园大床房', '大床房', '独自旅行', 118, 2, 5, 6, '["客房服务","房间设施","前台服务"]'::jsonb, '客房服务', '房间设施', '前台服务'),
('68027ccde3c98b0941765aa1', '老牌5星，感受最深的是，花园想做文创酒店，有自己的博物馆，有古仔讲。床品舒适，早餐建议桃园厅或者荔湾亭，一楼瀑布厅适合外国人的口味，主厨好像是西班牙的，中式茶点比2，3楼差好远。西点OK。', '["https://dimg04.c-ctrip.com/images/0230z12000cx64iy65988_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231s12000cx5dj6635FE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-12', '粤韵双床套房', '套房', '家庭亲子', 94, 0, 18, 8, '["餐饮设施","整体满意度","房间设施"]'::jsonb, '餐饮设施', '整体满意度', '房间设施'),
('68027ccde3c98b0941765aa2', '早就久闻花园酒店大名，这次来广州终于有机会入住。酒店到处摆满了鲜花，萦绕在鲜花中心情很好。最近适逢广交会，办理入住的人稍多，工作人员会准备小饼干和饮料给客人排队间隙等待时享用。感谢前台给我们升级了房型，入住的是粤韵客房。来得匆忙忘带手机充电线了，跟工作人员一说很快就送到了。本来担心浴缸会不干净但是发现自己想多了，卫生搞得还是很不错的。还去了酒店内的博物馆参观，这是一家讲述有关住宿业的博物馆，挺有新意的。酒店环境令人舒适满意，下次来广州还要入住！', '["https://dimg04.c-ctrip.com/images/0231l12000chmyeza85BC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232d12000chmsk0nDA8A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233c12000chn1ig39658_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233912000chmsk0pBA5F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232d12000chmzent4F62_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231d12000chmtp29FD02_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235212000chn4mteBE61_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234812000chn1ig5D012_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233y12000chmwy3f9CCA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-31', '红棉大床套房', '套房', '家庭亲子', 224, 1, 3, 9, '["整体满意度","前台服务","卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况'),
('68027ccde3c98b0941765aa3', '15:52	携程旅行	4G	
＜	点评详情	
总评分	5.0分	
设施分 5.0	环境分	5.0	卫生分	5.0	服务分	5.0	
2024-07-21发布于广东和家人出游
非常感谢rain小姐姐和客房服务劳拉帮了我们很多忙，妈妈带娃旅游中，给了我们很多帮助。rain还帮我们升级了小羊玩偶。孩子特别开心。劳拉教了我怎么用咖啡机，还帮孩子拿了适合的拖鞋。万分感谢??', '["https://dimg04.c-ctrip.com/images/0235k12000euoxsgb84B5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230r12000eup0g4fF59D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233z12000euozbdr1FBF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233f12000eup0g4lE60E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-07-21', '花园大床房', '大床房', '家庭亲子', 183, 0, 4, 8, '["前台服务","客房服务"]'::jsonb, '前台服务', '客房服务', NULL),
('68027ccde3c98b0941765aa4', '酒店位置在市区，位置很好，去附近的景点都很方便。 酒店房间干净，整洁，床品舒服柔软， 入住体验非常棒。重点表扬酒店的服务，因为飞机晚点到店时间特别晚，前台小姐姐帮忙升级了房型还延迟了退房； 另外LiVen 热情细致的协助我们解决各种在酒店遇到的问题，真的超贴心。', '["https://dimg04.c-ctrip.com/images/0237412000jqv5xek8E04_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232e12000jqvxz6b345C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235b12000jqwi2aeB014_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234i12000jqvuddv4996_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230112000jqv5xemDFF8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-04-12', '花园大床房', '大床房', '独自旅行', 131, 0, 25, 9, '["前台服务","整体满意度","交通便利性"]'::jsonb, '前台服务', '整体满意度', '交通便利性'),
('68027ccde3c98b0941765aa5', '很不错 每位服务人员都非常热情 房型也很好 带上妈妈爸爸和小朋友一起 每个人都很开心 小朋友可以喂鱼 爸爸妈妈觉得酒店也很好 准备以后去广州都住这里', '["https://dimg04.c-ctrip.com/images/0232112000d4gbwxaE78E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234v12000d4gpgq14A99_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-04', '花园双床房', '双床房', '家庭亲子', 74, 0, 4, 6, '["整体满意度","前台服务","房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施'),
('68027ccde3c98b0941765aa6', '第二次住花园了，整体环境还是很好的，就是这次行政酒廊搬到了楼上旋转餐厅分出来的一块地方，感觉还是一楼原来酒吧的位置更舒服还有室外位环境也好，楼上除了晚上能看到一点点广州塔没有什么风景，地方小也显得很局促，不知道是不是心理作用现在下午茶和happyhour没有在楼下时候丰富了，早餐也纯自助了以前在楼下还可以点单的，和一楼的瀑布早餐就没啥差别了。房间还是比较满意的岭客金卡给升了级，
服务：有一天牙疼在休息中午楼上不知道哪里在装修电钻声特别吵，打电话让前台沟通下等我们退房再钻，就这一件事反复打了四五个电话等了半小时才得到解决，本来想待到12点走不得不提前走了，这点让人不是很愉快', '["https://dimg04.c-ctrip.com/images/0236d12000cugpn1c1664_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230c12000cugou3t74F8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232012000cugl0t01831_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-01', '花园双床房', '双床房', '情侣出游', 289, 0, 4, 8, '["餐饮设施","安静程度","前台服务"]'::jsonb, '餐饮设施', '安静程度', '前台服务'),
('68027ccde3c98b0941765aa7', '酒店很高大上，入住正是圣诞节，一棵大大的圣诞树??装饰的很华丽。酒店的早餐环境非常有特色，大大的玻璃窗可以看到室外的瀑布，在这里就餐心情愉悦，早餐品种丰富多样，口味也不错??，连住两晚，第二天体验了三十层旋转餐厅的早餐，相比较而言更喜欢一口的环境。只可惜原本的下午茶??，2点退房后不可以享用，白白的浪费掉了，不然，正好吃完下午茶赶往机场都有时间，要是办理入住时提醒一下就好了，算是小小的遗憾吧。', '["https://dimg04.c-ctrip.com/images/0232712000cwc3agu50AE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233h12000cwc34tcF0CE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230j12000cwc22e27529_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230h12000cwc38qyEFD3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-09', '花园双床房', '双床房', '情侣出游', 198, 1, 1, 9, '["餐饮设施","整体满意度","前台服务"]'::jsonb, '餐饮设施', '整体满意度', '前台服务'),
('68027cd7e3c98b0941765aa8', '我们这次是带孩子去广州感受圣诞氛围的，酒店布置很漂亮，孩子也拍了很多美照！带着孩子去逛了酒店的博物馆，博物馆比较小，但酒店历史都浓缩在其中了！这次过去酒店最不好的体验是旁边在修地铁站，吵到没办法好好休息，晚上吵到十点多，早上不到八点就开工，这是这次出行最最不好的体验了！', '["https://dimg04.c-ctrip.com/images/0235c12000czs2u1e664A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233s12000czs5e17033C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234a12000czsjoez1074_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233u12000czs5fn86B65_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235912000czscavf7D00_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2024-01-21', '红棉大床套房', '套房', '家庭亲子', 135, 0, 5, 8, '["安静程度","周边配套","整体满意度"]'::jsonb, '安静程度', '周边配套', '整体满意度'),
('68027cd7e3c98b0941765aa9', '非常满意的一次住宿，带着爸妈和孩子奔着老牌酒店去的，住了四晚，我们定了两间房，赶上广州降温，还特意给我们升级了套房，服务一级棒超五星体验，谁住谁知道????????', '["https://dimg04.c-ctrip.com/images/0236412000d2aq2b9EF0A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-28', '花园双床房', '双床房', '家庭亲子', 82, 0, 15, 8, '["整体满意度","前台服务"]'::jsonb, '整体满意度', '前台服务', NULL),
('68027cd7e3c98b0941765aaa', '春节旅程结束最后住花园酒店，体验很好，加钱升级了亲子房房间，小朋友很开心。整体服务都不错，唯一不好的是办理入住和早餐需要排队。', '["https://dimg04.c-ctrip.com/images/0233y12000d7zi4tgA279_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000d7zhr2199DF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234q12000d7zgb160A9C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236n12000d7zi4u066C7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-16', '花园大床房', '大床房', '家庭亲子', 63, 0, 10, 7, '["整体满意度","退房/入住效率","餐饮设施"]'::jsonb, '整体满意度', '退房/入住效率', '餐饮设施'),
('68027cd7e3c98b0941765aab', '干净、周到、环境优美，到处飘着花香，卫生间，床单茶具都非常干净。早餐美味，用餐环境好，安静。服务到位。', '["https://dimg04.c-ctrip.com/images/0230312000dd32ts690EE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232512000dd2by4d1CEE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232012000dd2yh64DC04_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233x12000dd312ioAF13_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236w12000dd2xsb874A5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-03-07', '花园双床房', '双床房', '朋友出游', 51, 0, 4, 7, '["卫生状况","餐饮设施","安静程度"]'::jsonb, '卫生状况', '餐饮设施', '安静程度'),
('68027cd7e3c98b0941765aac', '房间整洁，服务态度好！因为订房时比实际入住房价高赠送了早餐！早餐非常美味！酒店花园是真漂亮，花团锦簇，锦鲤小桥瀑布美不胜收。', '["https://dimg04.c-ctrip.com/images/0230z12000da2ymzbEE4E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235a12000da2y9oeC912_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234s12000da2xyld5E48_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231312000da2yeoeD904_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234m12000da2xgq5FF40_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-24', '花园双床房', '双床房', '家庭亲子', 62, 0, 6, 8, '["整体满意度","餐饮设施","卫生状况"]'::jsonb, '整体满意度', '餐饮设施', '卫生状况'),
('68027cd7e3c98b0941765aad', '因为觉得住的还挺好所以续房一天，酒店正好重新装修一部分房间，让我们搬到粤韵房了，这个房间更新一些，床也更舒适，瀑布餐厅酒店早餐还不错，还赠送了水果，对酒店其他服务还都是很满意的，酒店的博物馆也很值得一看。', '["https://dimg04.c-ctrip.com/images/0204r12000csf2ks81475_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0231i12000csf03so7D2A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232912000cset8ly26F0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233212000csewtkd9F80_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-24', '城央绿意大床房', '大床房', '家庭亲子', 102, 0, 79, 7, '["房间设施","整体满意度","餐饮设施"]'::jsonb, '房间设施', '整体满意度', '餐饮设施'),
('68027cd7e3c98b0941765aae', '酒店位置很好，服务热情周到，春节期间布置的也是非常喜庆，活动很多，还送了鲜花~房间干净整洁，床品舒适。早餐在旋转餐厅，还是比较丰富哒', '["https://dimg04.c-ctrip.com/images/0234o12000d91cgkm1725_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231n12000d91bhwf13D3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-02-20', '花园双床房', '双床房', '家庭亲子', 66, 0, 14, 7, '["整体满意度","房间设施","餐饮设施"]'::jsonb, '整体满意度', '房间设施', '餐饮设施'),
('68027cd7e3c98b0941765aaf', '交通便利，地铁站上来就是北门口。服务人员众多，随时随地都能得到有效的帮助。客房整洁干净，布草，洗漱用品，洗澡水压等都令人满意。冲着官方白金五星来的，发现名不虚传。上午到达，前台的南希快速高效的办理了加床加餐的入住，入住后才发现还帮我升级了房型，感谢。客房服务无论是加床，还是我们几次要求送水送用品，其反应速度都是我入住各类高奢酒店以来最快的。早餐的出品可以，员工翻台也是高效。酒店博物馆也值得一观。最后感谢客房服务员拾金不昧，在我自己都没发觉时，值班经理已经联系我，让我的黄金手串失而复得。感谢！', '["https://dimg04.c-ctrip.com/images/0231p12000d07p7pi3376_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230w12000d07p2xv9DB0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231e12000d07or8m01D3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234d12000d07p7po6B38_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231s12000d07p2xx7602_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232a12000d07or8o5B7D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237112000d07p7pu7537_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232o12000d07p2xzC43A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234212000d07or8s7406_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-22', '红棉大床套房', '套房', '家庭亲子', 248, 0, 32, 9, '["前台服务","客房服务","交通便利性"]'::jsonb, '前台服务', '客房服务', '交通便利性'),
('68027cd7e3c98b0941765ab0', '过年来玩 之前住过一次 这次带爸妈来 这个房型有一个客厅可以加床还蛮适合家庭出行的 瀑布餐厅服务很好 年夜饭提前预定的桃园馆也很好吃', '["https://dimg04.c-ctrip.com/images/0231212000d677jva130D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232e12000d66urw692C5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236r12000d674bfw299D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-10', '红棉双床套房', '套房', '家庭亲子', 66, 0, 18, 7, '["房间设施","餐饮设施","整体满意度"]'::jsonb, '房间设施', '餐饮设施', '整体满意度'),
('68027cd7e3c98b0941765ab1', '时光荏苒，转眼间已是三年之隔，当我再次踏入广州花园酒店的大门，那份熟悉与温馨感油然而生，仿佛时间在这里悄然静止。酒店的服务依旧保持着那份一如既往的高水准，让人丝毫感觉不到岁月的流转。此次入住，我有幸遇到了前台的Niki小姐。她以花园酒店那标志性的热情笑容和细致入微的服务，瞬间驱散了我旅途的疲惫。在得知我是3年前入住过的客人后，Niki更是主动为我升级了房间至粤韵大床房，并贴心地赠送了两份早餐券。这份意外的惊喜，让我对酒店的好感倍增。另外值得一提的是，客房管家LiLi还特意准备了月饼和阳光玫瑰葡萄作为小礼物。这份意外的关怀，让我感受到了家的温暖。三年的时光并未改变花园酒店的品质与魅力，反而让它在我心中更加熠熠生辉。在未来的日子里，我还会再次选择这里，作为我旅途中的温馨港湾。', '["https://dimg04.c-ctrip.com/images/0234b12000eyimxt99FA6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230412000eyijk3c2551_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232k12000eyitdkz060C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234m12000eyivnhr670D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236q12000eyimk1vC170_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236j12000eyirguz1918_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-31', '花园大床房', '大床房', '商务出差', 340, 0, 10, 9, '["前台服务","整体满意度","客房服务"]'::jsonb, '前台服务', '整体满意度', '客房服务'),
('68027ce2e3c98b0941765ab2', '酒店很漂亮 餐厅也多 服务还特别好 不愧是老牌酒店 下次还来', '["https://dimg04.c-ctrip.com/images/0235h12000dohjzdk737B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-04-15', '城央绿意大床房', '大床房', '商务出差', 30, 0, 20, 5, '["整体满意度","餐饮设施","前台服务"]'::jsonb, '整体满意度', '餐饮设施', '前台服务'),
('68027ce2e3c98b0941765ab3', '房间很大，不过没有浴缸，淋浴和洗漱区有点小，到不影响房间舒适和整洁
早餐区域是瀑布餐厅，吃早饭看美景很不错
酒店没有和瀑布，可以去逛逛，没人，景色很美', '["https://dimg04.c-ctrip.com/images/0230712000d2c65tc2C4F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234b12000d2c9m1n2A75_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230e12000d2c6yopE381_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231m12000d2cadla8220_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-28', '花园双床房', '双床房', '家庭亲子', 75, 0, 11, 6, '["房间设施","餐饮设施","周边配套"]'::jsonb, '房间设施', '餐饮设施', '周边配套'),
('68027ce2e3c98b0941765ab4', '花园酒店，名副其实，酒店后花园的瀑布庭院还是蛮有气势的。不过酒店确实老了点，客房洗手台、淋浴房、卫生间布局感觉很不好，双人房半开放结构有干扰。', '["https://dimg04.c-ctrip.com/images/0230a12000dbzqsch8F1E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234912000dbzrjti79F1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230d12000dbzrvsh7E86_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230w12000dbzr70e2570_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2024-03-03', '花园双床房', '双床房', '商务出差', 71, 0, 17, 7, '["房间设施","景观/朝向"]'::jsonb, '房间设施', '景观/朝向', NULL),
('68027ce2e3c98b0941765ab5', '久违了，花园酒店，20几年前曾经住过，已经渐渐的淡忘了，此次来广州，查到花园酒店已经重新装修与改动了一些房型，便毫不犹豫的订了两晚。

花园酒店绝对的五星酒店中的翘楚，尽管是近40年前的产品，却是生机勃勃，老当益壮。
??论是房间的设施与硬件，都是超五星轻奢酒店标准，二楼的中餐厅环境也是一流的，特别是独特的的岭南风格的后花园（园林），那是人间仙境，白天迷人，夜晚诱人。
美中不足的是，大堂里飘散的香水味，也许选的不对我们的味觉，似乎??点澡堂子的味道，刺鼻而欠舒服。
若能下点功夫，调一下大堂香水味，让更多的客人喜欢，那么，来广州，花园酒店就是第一选择。', '["https://dimg04.c-ctrip.com/images/0204i12000crfm68t5395_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0231w12000crflcx1F60E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234k12000crfm9ca2B74_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233r12000crflaqt3AA7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232l12000crfllao4868_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233n12000crflqvr6298_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234712000crflew11929_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235r12000crfm3otC819_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232r12000crflxao9043_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234f12000crfldvyC360_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-19', '红棉大床套房', '套房', '情侣出游', 278, 0, 66, 9, '["房间设施","整体满意度","公共设施"]'::jsonb, '房间设施', '整体满意度', '公共设施'),
('68027ce2e3c98b0941765ab6', '非常满意的一次出游体验，前台Ariel美女给免费升级了套房，房间的欢迎水果质量也很好，老婆赞不绝口，房间看见花园瀑布，景色很好', '["https://dimg04.c-ctrip.com/images/0230c12000evjt8o2041E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-23', '花园大床房', '大床房', '情侣出游', 63, 0, 12, 8, '["前台服务","景观/朝向","整体满意度"]'::jsonb, '前台服务', '景观/朝向', '整体满意度'),
('68027ce2e3c98b0941765ab7', '设施：房间装修设施很好设备很新，房间很大
环境：酒店内部花园很漂亮，有假山瀑布锦鲤池
早餐很好吃，服务很到位，赠送了30楼行政酒廊的景观和服务都很好', '["https://dimg04.c-ctrip.com/images/0202e12000d1ruhukC2DB_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0233k12000d1roln06434_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232412000d1rcltt686A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-26', '花园双床房', '双床房', '家庭亲子', 74, 0, 15, 8, '["房间设施","餐饮设施","整体满意度"]'::jsonb, '房间设施', '餐饮设施', '整体满意度'),
('68027ce2e3c98b0941765ab8', '广州三家白金五星级酒店之一，博物馆详细介绍酒店历史，几乎所有的美女服务人员笑容满面，到处都是，不知为何，上上下下找不到免费入座的地方，连办理入住的地方有没有，老年人长时间站着吃不消。携程网套餐，免费升级到套房，下午茶升级到包含晚上的欢乐时光，非常享受，谢谢！瀑布餐厅自助早餐在上午9点左右竟然排队等候多时，可以学习海花岛酒店分时段就餐方法。花园不是很大，人工瀑布气势磅礴。老外很多，还有外籍服务生。', '["https://dimg04.c-ctrip.com/images/0234e12000cr8khar016B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231a12000cr8b73pF9ED_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233d12000cr8fr6rA484_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230912000cr8gpac2CDE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230612000cr8cfxv1B5D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234a12000cr89l4z75FF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230212000cr8c1vh0785_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-18', '花园双床房', '双床房', '家庭亲子', 199, 1, 105, 8, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('68027ce2e3c98b0941765ab9', '房间很好，升级了个套房，卫生服务各方面都很周到，第一次来，下次还来', '["https://dimg04.c-ctrip.com/images/0233912000dkgcmbt798D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233212000dkgc8qc958D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-04-02', '花园大床房', '大床房', '商务出差', 33, 0, 9, 6, '["整体满意度","房间设施","卫生状况"]'::jsonb, '整体满意度', '房间设施', '卫生状况'),
('68027ce2e3c98b0941765aba', '广州花园酒店给我的入住体验特别好，走入大堂，映入眼帘是以红楼梦为主题的金碧辉煌的壁画，回眸又见岭南水乡人民生活的生动画面，由于入住的时间离圣诞节很近，节日气氛非常浓郁，入住的客人也特别多，美丽的服务员和蔼可亲，而且心特别细，远远看到客人乘电梯，都会主动为你按好，真正做到客人至上，让人感觉特别舒服。至于它的后花园，绝对有特色，两条18米高的大瀑布从天而降，大气磅礴。因为喜欢，故1月份带着家人再游广州，又订了4晚。', '["https://dimg04.c-ctrip.com/images/0236112000csrkwdhF0BE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232312000csrlic6A19E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235v12000csran5a5880_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235n12000csrlzor9562_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-25', '花园大床房', '大床房', '家庭亲子', 207, 0, 5, 9, '["整体满意度","前台服务","公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施'),
('68027ce2e3c98b0941765abb', '酒店生意很好，接待的先生也很热情、专业。
早餐也很不错，丰富而精致
房间布局合理、干净。客房服务有待改善，多要了几瓶水，说是有限制的。1100多元的房费不应该这样', '["https://dimg04.c-ctrip.com/images/0233c12000cx84h971F48_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231p12000cx838tnDEBA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231812000cx7z86nDBF3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-12', '花园大床房', '大床房', '其他', 81, 0, 76, 6, '["餐饮设施","客房服务","整体满意度"]'::jsonb, '餐饮设施', '客房服务', '整体满意度'),
('68027ceee3c98b0941765abc', '订的套餐，重新装修后的房间很大，也维持的很新，有JBL信箱，床头有USB插头，两个洗面盆，17层景观很好，往下能看见瀑布，远景是城市建筑，美中不足的是给我的房间没有浴缸，其他的都很好！早餐后逛一逛瀑布花园很舒服～有机会会再去～', '["https://dimg04.c-ctrip.com/images/0232c12000cqn38w0C3E9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230t12000cqn38ni3E90_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232712000cqn3710700C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235012000cqn2yi5C8F9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235312000cqn3a3k74F2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-12-15', '红棉双床套房', '套房', '朋友出游', 113, 0, 7, 9, '["房间设施","景观/朝向","整体满意度"]'::jsonb, '房间设施', '景观/朝向', '整体满意度'),
('68027ceee3c98b0941765abd', '老贵族一样，尽管有让人不那么称心的地方，但气质非凡，服务规范周到。
其实花园酒店完全没必要和别人做比较。', '["https://dimg04.c-ctrip.com/images/0235x12000daozdd7C20E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235h12000daozvn4B292_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233g12000daoz9o971E4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-02-26', '花园双床房', '双床房', '情侣出游', 52, 0, 9, 6, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027ceee3c98b0941765abe', '第一次来花园酒店，非常舒适惬意的一次入住，无论服务，环境，卫生，餐食，都很满意，尤其酒店设计风格和设施，传统华丽又时尚优雅，下次还会再来！好赞??????', '["https://dimg04.c-ctrip.com/images/0230i12000cztyn251C08_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234x12000cztyqqm29BE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231512000cztymy94095_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236612000cztykbi7019_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237312000cztyph683CD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-21', '红棉大床套房', '套房', '家庭亲子', 77, 0, 22, 7, '["整体满意度","房间设施","卫生状况"]'::jsonb, '整体满意度', '房间设施', '卫生状况'),
